mapper.select:
SELECT OBJECTID AS objectId, NAME AS tableNameCh, TABLENAME AS tableNameEn, SJXJBM AS resourceIdentify FROM CLASSIFY_INTERFACE_ALL_DATE WHERE SJXJBM IS NOT NULL AND objectstate = 1
AND (PRIMARYORGANIZATIONCH = #{primaryClassifyCh} OR SECONDARYORGANIZATIONCH = #{primaryClassifyCh})
AND PRIMARYORGANIZATIONCH = #{primaryClassifyCh}
AND SECONDARYORGANIZATIONCH = #{secondaryClassifyCh}
AND CONCAT(#{sjzzflCodeId}, SJYJFLCODENAME, SJEJFLCODENAME) = #{classifyid}
AND CONCAT(#{sjzzflCodeId}, SJYJFLCODENAME, SJEJFLCODENAME, SJSJFLCODENAME) = #{classifyid}
AND ( UPPER(NAME) LIKE CONCAT(UPPER('%'), #{search}, '%') OR UPPER(TABLENAME) LIKE CONCAT(UPPER('%'), #{search}, '%') OR UPPER(SJXJBM) LIKE CONCAT(UPPER('%'), #{search}, '%') )

SELECT SJXJBM AS resourceIdentify, YYYXTJSGS AS manufacturer, SJZYSQDWMC AS authority FROM SYNLTE.PUBLIC_DATA_INFO WHERE SJXJBM IS NOT NULL AND (YYYXTJSGS IS NOT NULL OR SJZYSQDWMC IS NOT NULL)
AND YYYXTJSGS = #{manufacturer}
AND SJZYSQDWMC = #{authority}

SELECT SJXJBM AS resourceIdentify, CONCAT(TABLE_TYPE, '.', TABLE_PROJECT) AS storageLocation, TABLE_ALL_COUNT AS dataNum, register_state AS registerState, resourceId FROM ( SELECT j.SJXJBM, j.TABLE_TYPE, j.TABLE_PROJECT, j.TABLE_ALL_COUNT, j.register_state, j.resourceId, ROW_NUMBER() OVER (PARTITION BY LOWER(TABLE_PROJECT), UPPER(TABLE_NAME_EN) ORDER BY STATISTICS_TIME DESC) AS rnn FROM DP_TABLE_ORGANIZATION_ASSETS j WHERE PRIMARY_ORGANIZATION_CH = #{primaryClassifyCh}
AND SECONDARY_ORGANIZATION_CH = #{secondaryClassifyCh}
AND THREELEVEL_ORGANIZATION_CH = #{secondaryClassifyCh}
AND (UPPER(TABLE_TYPE) IN ('ODPS', 'CLICKHOUSE') OR UPPER(TABLE_TYPE) LIKE '%HIVE%') AND STATISTICS_TIME >= date(NOW()) - INTERVAL #{daysAgo} DAY ) h WHERE h.rnn = 1

SELECT objectId, resourceIdentify, tableNameEn, tableNameCh, storageLocation, dataCenter, dataNum, registerState, resourceId FROM ( SELECT ciad.objectId AS objectId, toa.sjxjbm AS resourceIdentify, ciad.tablename AS tableNameEn, ciad.sjxjzwmc AS tableNameCh, CONCAT(UPPER(toa.table_type), '.', UPPER(toa.table_project)) AS storageLocation, toa.res_name AS dataCenter, toa.table_all_count AS dataNum, toa.register_state AS registerState, toa.resourceId, ciad.yj, ciad.ej, ciad.sj FROM ( SELECT h.* FROM ( SELECT sjxjbm, table_type, table_project, table_name_en, table_all_count, register_state, resourceId, res_name, ROW_NUMBER() OVER (PARTITION BY UPPER(table_type), UPPER(table_project), UPPER(table_name_en) ORDER BY statistics_time DESC) AS rnn FROM DP_TABLE_ORGANIZATION_ASSETS WHERE statistics_time >= date(NOW()) - INTERVAL #{daysAgo} DAY ) h WHERE h.rnn = 1 ) toa LEFT JOIN ( SELECT DISTINCT objectid AS objectId, sjxjbm AS sjxjbm1, sjxjzwmc, tablename, primaryorganizationch AS yj, firstorganizationch AS ej, secondaryorganizationch AS sj FROM classify_interface_all_date ) ciad ON toa.sjxjbm COLLATE utf8mb4_unicode_ci = ciad.sjxjbm1 COLLATE utf8mb4_unicode_ci ) t
AND (yj = #{primaryClassifyCh} OR ej = #{primaryClassifyCh})
AND yj = #{primaryClassifyCh}
AND ej = #{secondaryClassifyCh}
AND sj = #{secondaryClassifyCh}
AND ( UPPER(tableNameEn) LIKE CONCAT(UPPER('%'), #{search}, '%') OR UPPER(tableNameCh) LIKE CONCAT(UPPER('%'), #{search}, '%') OR UPPER(resourceIdentify) LIKE CONCAT(UPPER('%'), #{search}, '%') )
